Here's my pipe function:

    function loadNewsPage(tableState, tableController) {
			vm.isLoading = true;
			var pageNumber = tableState ? tableState.pagination.start / tableState.pagination.number + 1 : 1;
			var newsPerPage = tableState ? tableState.pagination.number : 20;

			newsService.getPageNewsAsync(pageNumber, newsPerPage).then(
					function (data) {
						// data.totalNews
						// data.pageNum,
						// data.newsPerPage
						vm.totalPages = Math.ceil(data.totalNews / data.newsPerPage);
						if (tableController) {
							tableController.tableState().pagination.numberOfPages = vm.totalPages;
