Using `metaclass` for decorating seems to solve the issue @droope and @bhoomit are facing

```python
def class_decorating_meta(prefix, *decorators):
    '''
    modified from: http://stackoverflow.com/a/6308016
    '''
    class DecoratingMetaclass(type):
        def __new__(self, class_name, bases, namespace):
            for key, value in list(namespace.items()):
                if not key.startswith(prefix):
                    continue
                if not callable(value):
                    continue
                for decorator in decorators:
                    value = decorator(value)
                namespace[key] = value

            return type.__new__(self, class_name, bases, namespace)

    return DecoratingMetaclass
```

Usage:
```python
class TestStuff(TestCase):
    __metaclass__ = class_decorating_meta(
        'test_',
        responses.activate)

    def test_one(self):
        pass
```

